 To achieve this in Go, you can use the `github.com/go-redis/redis/v8` package to interact with Redis. You'll need to use a combination of `GET`, `SET`, and `WATCH` commands to ensure that the object is only stored if the version is newer than the one already in Redis.

Here's a sample code snippet to demonstrate this:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"

	"github.com/go-redis/redis/v8"
)

type Object struct {
	Value   string `json:"value"`
	Version int    `json:"version"`
}

func main() {
	ctx := context.Background()

	// Initialize Redis client
	rdb := redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	// Example object to store
	obj := Object{
		Value:   "example value",
		Version: 2,
	}

	key := "myobject"

	// Store the object in Redis if the version is newer
	err := storeIfNewerVersion(ctx, rdb, key, obj)
	if err != nil {
		log.Fatalf("Failed to store object: %v", err)
	}

	fmt.Println("Object stored successfully")
}

func storeIfNewerVersion(ctx context.Context, rdb *redis.Client, key string, obj Object) error {
	// Get the current object from Redis
	currentObj, err := getObject(ctx, rdb, key)
	if err != nil && err != redis.Nil {
		return err
	}

	// If the current object exists and its version is greater than or equal to the new object's version, do nothing
	if currentObj != nil && currentObj.Version >= obj.Version {
		fmt.Println("Current version is not older, skipping update")
		return nil
	}

	// Serialize the new object to JSON
	objData, err := json.Marshal(obj)
	if err != nil {
		return err
	}

	// Use a transaction to ensure atomicity
	txf := func(tx *redis.Tx) error {
		// Watch the key to ensure it hasn't changed
		_, err := tx.TxPipelined(ctx, func(pipe redis.Pipeliner) error {
			pipe.Watch(ctx, key)
			return nil
		})
		if err != nil {
			return err
		}

		// Set the new object
		_, err = tx.TxPipelined(ctx, func(pipe redis.Pipeliner) error {
			pipe.Set(ctx, key, objData, 0)
			return nil
		})
		return err
	}

	// Execute the transaction
	err = rdb.Watch(ctx, txf, key)
	if err != nil {
		return err
	}

	return nil
}

func getObject(ctx context.Context, rdb *redis.Client, key string) (*Object, error) {
	result, err := rdb.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, nil
		}
		return nil, err
	}

	var obj Object
	err = json.Unmarshal(result, &obj)
	if err != nil {
		return nil, err
	}

	return &obj, nil
}
```

### Explanation:

1. **Initialization**: The Redis client is initialized with the appropriate connection details.
2. **Object Definition**: An example object is defined with a value and a version.
3. **Store Function**: The `storeIfNewerVersion` function checks if the current version in Redis is older than the new object's version. If it is, it updates the object in Redis.
4. **Transaction**: The function uses a Redis transaction to ensure atomicity. It watches the key to prevent concurrent modifications.
5. **Get Function**: The `getObject` function retrieves the current object from Redis and deserializes it from JSON.

This code ensures that the object is only stored in Redis if the version is newer than the version already present.

