To achieve this, you can use the `HSETNX` command in Redis, which sets the value of a hash field only if the field does not exist. In this case, we'll use a hash to store the object's value and version. We'll first check if the version in Redis is older than the given version, and if so, update the value. Here's the Golang code using the `go-redis` library:

```go
import (
	"context"
	"fmt"
	"strconv"

	"github.com/go-redis/redis/v8"
)

type Object struct {
	Value   string
	Version int
}

func StoreObjectIfNewer(ctx context.Context, redisClient *redis.Client, key string, obj Object) error {
	// Get the current version from Redis
	currentVersionStr, err := redisClient.HGet(ctx, key, "version").Result()
	if err != nil && err != redis.Nil {
		return fmt.Errorf("error getting current version: %w", err)
	}

	// If the key doesn't exist, set the value and version
	if err == redis.Nil {
		return redisClient.HMSet(ctx, key, map[string]interface{}{
			"value":   obj.Value,
			"version": obj.Version,
		}).Err()
	}

	// Parse the current version
	currentVersion, err := strconv.Atoi(currentVersionStr)
	if err != nil {
		return fmt.Errorf("error parsing current version: %w", err)
	}

	// If the given version is newer, update the value
	if obj.Version > currentVersion {
		return redisClient.HMSet(ctx, key, map[string]interface{}{
			"value":   obj.Value,
			"version": obj.Version,
		}).Err()
	}

	return nil
}
```

This function first checks if the key exists in Redis. If it doesn't, it sets the value and version. If it does, it compares the given version with the current version in Redis and updates the value if the given version is newer.

