        for (int i = 0; i < words.length / 2; i++) {
            String temp = words[i];
            words[i] = words[words.length - i - 1];
            words[words.length - i - 1] = temp;
        }

        StringBuilder encryptedStringBuilder = new StringBuilder();
        for (String word : words) {
            String reversedWord = new StringBuilder(word).reverse().toString();
            for (int i = 0; i < reversedWord.length() - 1; i++) {
                encryptedStringBuilder.append(reversedWord.charAt(i)).append(reversedWord.charAt(0));
            }
            encryptedStringBuilder.append(reversedWord.charAt(reversedWord.length() - 1));
            encryptedStringBuilder.append(" ");
        }

        // Correct the last step of the encryption process
