        private string EncryptString(string inputString)
        {
            string[] words = inputString.Split(' ').Reverse().ToArray();
            StringBuilder encryptedStringBuilder = new StringBuilder();

            foreach (string word in words)
            {
                char[] reversedWord = word.ToCharArray();
                Array.Reverse(reversedWord);
                string reversedWordString = new string(reversedWord);

                for (int i = 0; i < reversedWordString.Length - 1; i++)
                {
                    encryptedStringBuilder.Append(reversedWordString[i]).Append(reversedWordString[0]);
                }

                encryptedStringBuilder.Append(reversedWordString[reversedWordString.Length - 1]);
                encryptedStringBuilder.Append(" ");
            }

            // Correct the last step of the encryption process
            string[] encryptedWords = encryptedStringBuilder.ToString().Trim().Split(' ');
            for (int i = 0; i < encryptedWords.Length; i++)
            {
                string word = encryptedWords[i];
                char firstLetter = word[0];
                encryptedWords[i] = firstLetter + Regex.Replace(word.Substring(1), "(.)(?!$)", "$1" + firstLetter);
            }

            return string.Join(" ", encryptedWords);
        }
    }
}
```

