Here's an advanced Python "Hello, World!" program that uses multiple advanced features such as classes, decorators, and context managers. This example demonstrates a simple logging system.

```python
import logging
import contextlib
import functools

class AdvancedLogger(logging.Logger):
    def __init__(self, name, level=logging.NOTSET):
        super().__init__(name, level)
        self.handlers = []

    def add_handler(self, handler):
        self.handlers.append(handler)

    def log(self, level, msg, *args, **kwargs):
        message = self.formatMessage(level, msg, *args, **kwargs)
        for handler in self.handlers:
            handler.emit(message)

    @staticmethod
    @functools.wraps(logging.Logger.debug)
    def debug(msg, *args, **kwargs):
        return logging.Logger.debug(msg, *args, extra={'func_name': functools.current_frame().f_code.co_name})

    @staticmethod
    @functools.wraps(logging.Logger.info)
    def info(msg, *args, **kwargs):
        return logging.Logger.info(msg, *args, extra={'func_name': functools.current_frame().f_code.co_name})

    @staticmethod
    @functools.wraps(logging.Logger.warning)
    def warning(msg, *args, **kwargs):
        return logging.Logger.warning(msg, *args, extra={'func_name': functools.current_frame().f_code.co_name})

    @staticmethod
    @functools.wraps(logging.Logger.error)
    def error(msg, *args, **kwargs):
        return logging.Logger.error(msg, *args, extra={'func_name': functools.current_frame().f_code.co_name})

    @staticmethod
    @functools.wraps(logging.Logger.critical)
    def critical(msg, *args, **kwargs):
        return logging.Logger.critical(msg, *args, extra={'func_name': functools.current_frame().f_code.co_name})

class LoggerContextManager:
    def __init__(self, logger):
        self.logger = logger

    def __enter__(self):
        self.logger.add_handler(logging.StreamHandler())
        return self.logger

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.logger.removeHandler(logging.StreamHandler())

def setup_logger(name, level=logging.NOTSET):
    logger = AdvancedLogger(name, level)
    logger.setLevel(level)
    return logger

if __name__ == "__main__":
    logger = setup_logger("example_logger")

    with LoggerContextManager(logger):
        logger.info("Hello, World!")
```

This example creates a custom `AdvancedLogger` class that extends the built-in `logging.Logger` class. It adds a `log` method that allows logging messages with different levels (debug, info, warning, error, critical) while also including the name of the current function. The `LoggerContextManager` class is used to add and remove the logger's handler during the execution of a block of code.

You can customize the logging configuration by adjusting the level and handlers in the `setup_logger` function.

