5. **Implement the ShoppingCart:**

Create the implementation of the shopping cart aggregate root. Use the CRTP to make the shopping cart a template class that derives from itself. This allows the shopping cart to access its own interface.

```cpp
// ShoppingCartImpl.h
#pragma once
#include "ShoppingCart.h"
#include "ProductVisitor.h"
#include <vector>
#include <unordered_map>
#include "IProduct.h"

template <typename Derived>
class ShoppingCartImpl : public ShoppingCart {
public:
    ShoppingCartImpl() = default;

    void addProduct(std::shared_ptr<IProduct> product) override {
        products_[product->getId()] = product;
    }

    void removeProduct(const std::string& productId) override {
        products_.erase(productId);
    }

    Money calculateTotal() const override {
        Money total(0.0);
        for (const auto& product : products_) {
            product.second->accept(*this);
            total += product.second->getPrice();
        }
        return total;
    }

    void accept(ShoppingCartVisitor& visitor) override {
        visitor.visit(*this);
    }

private:
    std::unordered_map<std::string, std::shared_ptr<IProduct>> products_;
};
```

6. **Implement the ShoppingCartVisitor:**

Create the implementation of the shopping cart visitor. This visitor will update the total price of the shopping cart when visiting each product.

```cpp
// ShoppingCartVisitorImpl.h
