Here's a Gradle task that should accomplish what you're looking for. This task uses the Git version control system to revert your code to a previous state, run your tests, and then revert back to the initial state. Make sure you have Git installed and properly configured on your system.

Add the following task to your `build.gradle` file:

```groovy
task revertAndTest(type: GradleBuild) {
    group "Verification"
    description "Revert code to previous state, run tests, and revert back"

    doFirst {
        // Checkout the previous commit before the last migration
        exec {
            commandLine 'git', 'checkout', 'HEAD~1'
        }
    }

    tasks = ['test']

    doLast {
        // Checkout the initial state after tests are done
        exec {
            commandLine 'git', 'checkout', 'HEAD'
        }
